import React, { useEffect, useState } from "react";
import axiosInstance from "../lib/instance";

function YourStores() {
  const [stores, setStores] = useState([]);
  const [loading, setLoading] = useState(false);

  // ✅ Fetch logged-in user's stores
  const fetchMyStores = async () => {
    setLoading(true);
    try {
      const res = await axiosInstance.get("/your-stores"); // adjust if needed

      console.log("My Stores:", res.data);

      if (res?.data?.stores) {
        setStores(res.data.stores);
      }
    } catch (error) {
      console.error("Fetch my stores error:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchMyStores();
  }, []);

  return (
    <div>
      <h2 className="text-xl font-bold mb-4">Your Stores</h2>

      {loading ? (
        <p>Loading...</p>
      ) : stores.length > 0 ? (
        stores.map((store) => (
          <div
            key={store.id}
            className="bg-white p-4 rounded shadow mb-6"
          >
            {/* Store Info */}
            <div className="mb-4">
              <h3 className="text-lg font-semibold">{store.name}</h3>
              <p className="text-gray-600">{store.address}</p>

              <p className="mt-2 font-medium">
                ⭐ Avg Rating:{" "}
                {store.averageRating !== undefined
                  ? store.averageRating.toFixed(1)
                  : 0}
              </p>
            </div>

            {/* Ratings Table */}
            <h4 className="font-semibold mb-2">
              Users who rated this store
            </h4>

            <table className="w-full text-center border">
              <thead className="bg-indigo-600 text-white">
                <tr>
                  <th>User Name</th>
                  <th>Email</th>
                  <th>Rating</th>
                </tr>
              </thead>

              <tbody>
                {store.ratings && store.ratings.length > 0 ? (
                  store.ratings.map((r, index) => (
                    <tr key={index} className="border-b">
                      <td>{r.user?.name}</td>
                      <td>{r.user?.email}</td>
                      <td>{r.value}</td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="3">No ratings yet</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        ))
      ) : (
        <p>No stores found</p>
      )}
    </div>
  );
}

export default YourStores;
